UDKGame.ini.content:
[Engine.GameInfo]
DefaultGameType=RenX_Game.Rx_Game
DefaultGame=RenX_Game.Rx_Game
DefaultServerGame=RenX_Game.Rx_Game
PlayerControllerClassName=RenX_Game.Rx_Controller
MaxPlayers={gameserver.slot_limit}
MaxSpectators={config_parameter id="max_spectators"}
GameDifficulty=+1.0
bAdminCanPause={config_parameter id="admin_can_pause"}

[Engine.GameReplicationInfo]
ServerName={gameserver.list_name}
MessageOfTheDay={config_parameter id="motd"}

[Engine.AccessControl]
AdminPassword={config_parameter id="admin_password"}
GamePassword={config_parameter id="server_password"}
IPPolicies=ACCEPT;*

[UTGame.UTGame]
bForceRespawn={config_parameter id="force_respawn"}
bPlayersMustBeReady={config_parameter id="players_must_be_ready"}
NetWait={config_parameter id="net_wait"}
MinNetPlayers={config_parameter id="min_net_players"}
bWaitForNetPlayers={config_parameter id="wait_for_net_players"}
RestartWait={config_parameter id="restart_wait"}
ClientProcessingTimeout={config_parameter id="client_processing_timeout"}
; Map rotation is generated from the Map Rotation parameter at launch.

UDKEngine.ini.content:
[URL]
MapExt=udk
Map=RenX-MenuMap.udk
LocalMap={config_parameter id="map"}.udk
Port={gameserver.game_port}
PeerPort={gameserver.raw_port}

[IpDrv.TcpNetDriver]
AllowDownloads={config_parameter id="allow_downloads"}
MaxClientRate={config_parameter id="max_client_rate"}
MaxInternetClientRate={config_parameter id="max_internet_client_rate"}
NetServerMaxTickRate={config_parameter id="server_tick_rate"}

[IpDrv.HTTPDownload]
ConnectionTimeout={config_parameter id="download_timeout"}
RedirectToURL={config_parameter id="redirect_url"}
UseCompression={config_parameter id="redirect_use_compression"}

[OnlineSubsystemSteamworks.OnlineSubsystemSteamworks]
bEnableSteam={config_parameter id="enable_steam"}
QueryPort={gameserver.query_port}
bUseVAC={config_parameter id="use_vac"}
Region=255
ServerBrowserTimeout=10

